prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?mf ?name ?sourceRef ?targetRef ?messageRef WHERE {
  ?mf a bboExt:MessageFlow .
  OPTIONAL { ?mf bbo:name ?name . }
  OPTIONAL { ?mf bboExt:sourceRef ?sourceRef . }
  OPTIONAL { ?mf bboExt:targetRef ?targetRef . }
  OPTIONAL { ?mf bboExt:messageRef ?messageRef . }
  ?mf tai:belongsTo ?choreo .
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "4fba0078103d44d9846d4fbec51710cb" .
}
LIMIT 20

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?message ?type ?name WHERE {
  ?message a bboExt:Message .
  OPTIONAL { ?message bbo:name ?name . }
}
LIMIT 10
